const sd = $getWorkflowStaticData('global');
const msg = $input.item.json.message;
const cid = msg.chat.id;
const mid = msg.message_id;
const now = Date.now();

const txt = msg.text || '';
if (!sd.buffers) sd.buffers = {};
if (!sd.buffers[cid]) sd.buffers[cid] = {messages:[], lastUpdate:now, processedIds:[]};
const b = sd.buffers[cid];
if (b.processedIds.includes(mid)) return [];
b.messages.push({id:mid, text:txt, ts:now});
b.lastUpdate = now;
await new Promise(r => setTimeout(r, 3100));
const cb = sd.buffers[cid];
if (cb.lastUpdate > now) return [];
const combined = cb.messages.map(m=>m.text).join('');
const ids = cb.messages.map(m=>m.id);
cb.processedIds = [...cb.processedIds, ...ids].slice(-50);
cb.messages = [];
if (!combined || combined.trim() === '') return [];
return [{json:{chat_id:cid, combined_text:combined}}];

const dec = b => b ? Buffer.from(b,'base64').toString('utf-8') : '';
const c = $('GitHub Get File').item.json;
const p = $('GitHub Get File1').item.json;
const l = $('GitHub Get File2').item.json;
const db = $('Debounce Buffer').item.json;
return [{json:{
  chat_id:db.chat_id, combined_text:db.combined_text,
  contextContent:dec(c.content), contextSha:c.sha || '',
  projectContent:dec(p.content), projectSha:p.sha || '',
  logContent:dec(l.content), logSha:l.sha || ''
}}];

const out = $('AI Agent').item.json.output;
const b = $('Bundle Files').item.json;
const fm = {
  'MAXIMUS_CONTEXT.md':{content:b.contextContent, sha:b.contextSha},
  'RRS_CADENCE_PROJECT.md':{content:b.projectContent, sha:b.projectSha},
  'RRS_CADENCE_LOG.md':{content:b.logContent, sha:b.logSha}
};
const re = /UPDATE_FILE:\s*(.+?)\nSECTION:\s*(.+?)\nACTION:\s*(.+?)\nCONTENT:\s*([\s\S]+?)\nEND_UPDATE/g;
const ups = [];
let m;
while ((m = re.exec(out)) !== null) {
  const fp = m[1].trim(), sec = m[2].trim(), act = m[3].trim().toUpperCase(), nc = m[4].trim();
  if (!fm[fp]) throw new Error(`Unknown file: ${fp}`);
  const f = fm[fp];
  const es = sec.replace(/[.*+?^${}()|[\]\\]/g,'\\$&');
  const sr = new RegExp(`(##\\s+${es}[\\s\\S]*?)(\\n##\\s|$)`,'i');
  const sm = f.content.match(sr);
  if (!sm) throw new Error(`Section "${sec}" not found in ${fp}`);
  let uf;
  if (act === 'APPEND') uf = f.content.replace(sm[1], sm[1].trimEnd()+'\n\n'+nc+'\n');
  else if (act === 'REPLACE') uf = f.content.replace(sm[1], sm[1].split('\n')[0]+'\n\n'+nc+'\n');
  else throw new Error(`Bad action: ${act}`);
  const today = new Date().toISOString().split('T')[0];
  uf = uf.replace(/(\*\*Last updated:\*\*)\s*\d{4}-\d{2}-\d{2}/, `$1 ${today}`);
  ups.push({filePath:fp, section:sec, action:act, sha:f.sha, updatedContent:uf, commitMessage:`Maximus: ${act.toLowerCase()} ${sec} in ${fp}`});
  fm[fp].content = uf;
}
if (!ups.length) throw new Error('No valid UPDATE_FILE blocks');
return ups.map(u => ({json:{...u, chat_id:b.chat_id}}));

const items = $input.all();
const upd = items[0].json.commitMessage !== undefined;
let reply, cid;
if (upd) {
  reply = items.map(i => `✅ ${i.json.action==='APPEND'?'Logged to':'Updated'} ${i.json.section} in ${i.json.filePath}\nSHA: ${i.json.commit?.sha?.substring(0,7)||'?'}`).join('\n\n');
  cid = items[0].json.chat_id;
} else {
  reply = $('AI Agent').item.json.output;
  cid = $('Bundle Files').item.json.chat_id;
}
const MAX = 4000;
const chunks = [];
let r = reply;
while (r.length > MAX) {
  let s = r.lastIndexOf('\n\n', MAX);
  if (s === -1) s = r.lastIndexOf('\n', MAX);
  if (s === -1) s = MAX;
  chunks.push(r.slice(0,s));
  r = r.slice(s).trimStart();
}
if (r.length) chunks.push(r);
return chunks.map((t,i) => ({json:{chat_id:cid, text:chunks.length>1?`(${i+1}/${chunks.length}) ${t}`:t}}));

const msg = $input.item.json.message;
const chatId = msg.chat.id;
const messageId = msg.message_id;

if (msg.text) {
  return [{ json: { message: { chat: { id: chatId }, message_id: messageId, text: msg.text }, pendingFileId: '' } }];
}

if (msg.document) {
  const fileName = msg.document.file_name || '';
  const mimeType = msg.document.mime_type || '';
  const fileId = msg.document.file_id;
  const allowed = ['text/plain', 'text/markdown'];
  const allowedExt = ['.txt', '.md'];
  const isAllowed = allowed.includes(mimeType) || allowedExt.some(ext => fileName.toLowerCase().endsWith(ext));

  if (!isAllowed) {
    return [{ json: { message: { chat: { id: chatId }, message_id: messageId, text: '[FILE REJECTED: ' + fileName + ' — only .txt and .md supported]' }, pendingFileId: '' } }];
  }

  return [{ json: { message: { chat: { id: chatId }, message_id: messageId, text: '' }, pendingFileId: fileId, pendingFileName: fileName } }];
}

return [{ json: { message: { chat: { id: chatId }, message_id: messageId, text: '[UNSUPPORTED MESSAGE TYPE]' }, pendingFileId: '' } }];

const binaryData = $input.item.binary.data;
const fileText = Buffer.from(binaryData.data, 'base64').toString('utf-8');
const fileName = $('Resolve Input').item.json.pendingFileName;
const chatId = $('Resolve Input').item.json.message.chat.id;
const messageId = $('Resolve Input').item.json.message.message_id;

if (fileText.length > 100000) {
  return [{ json: { message: { chat: { id: chatId }, message_id: messageId, text: '[FILE TOO LARGE: ' + fileName + ' is ' + fileText.length + ' chars, limit 100000]' } } }];
}

return [{ json: { message: { chat: { id: chatId }, message_id: messageId, text: '[FILE: ' + fileName + ']\n\n' + fileText } } }];
